import React, { useState, useEffect } from 'react';
import api from '../api/axios';

const CategoryDetail = () => {
  const [categories, setCategories] = useState([]);
  const [id, setId] = useState('');
  const [name, setName] = useState('');

  useEffect(() => { apiGetCategories(); }, []);
  const apiGetCategories = async () => { const res = await api.get('/categories'); setCategories(res.data); };

  const btnAddClick = async (e) => {
    e.preventDefault();
    const res = await api.post('/categories', { name });
    if (res.data.success) { alert('OK'); apiGetCategories(); }
  };
  const btnUpdateClick = async (e) => {
    e.preventDefault();
    const res = await api.put('/categories/' + id, { name });
    if (res.data.success) { alert('OK'); apiGetCategories(); }
  };
  const btnDeleteClick = async (item) => {
    if (window.confirm('Xóa?')) {
      const res = await api.delete('/categories/' + item._id);
      if (res.data.success) { alert('OK'); apiGetCategories(); }
    }
  };

  return (
    <div>
      <div className="float-left">
        <table border="1">
          <thead><tr><th>ID</th><th>Name</th><th>Action</th></tr></thead>
          <tbody>
            {categories.map((item) => (
              <tr key={item._id} onClick={() => { setId(item._id); setName(item.name); }}>
                <td>{item._id}</td><td>{item.name}</td>
                <td><button onClick={() => btnDeleteClick(item)}>Delete</button></td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
      <div className="float-right">
        <form>
            ID: <input type="text" value={id} readOnly /><br/>
            Name: <input type="text" value={name} onChange={(e) => setName(e.target.value)} /><br/>
            <button onClick={btnAddClick}>ADD</button>
            <button onClick={btnUpdateClick}>UPDATE</button>
        </form>
      </div>
    </div>
  );
};
export default CategoryDetail;
